const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// In-memory repositories
const projectsRepo = {};
const membersRepo = {};
const tasksRepo = {};
const commentsRepo = {};

// Health endpoint
app.get('/health', (req, res) => {
  res.status(200).json({ ok: true });
});

// Projects routes
const projectsRoutes = require('./modules/projects/routes');
projectsRoutes(app, { projectsRepo, membersRepo, tasksRepo, commentsRepo, crypto });

// Tasks routes
const tasksRoutes = require('./modules/tasks/routes');
tasksRoutes(app, { projectsRepo, membersRepo, tasksRepo, commentsRepo, crypto });

// Members routes
const membersRoutes = require('./modules/members/routes');
membersRoutes(app, { projectsRepo, membersRepo, tasksRepo, commentsRepo, crypto });

// Comments routes
const commentsRoutes = require('./modules/comments/routes');
commentsRoutes(app, { projectsRepo, membersRepo, tasksRepo, commentsRepo, crypto });

module.exports = app;

const app = require('./app');
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

module.exports = (app, { projectsRepo, crypto }) => {
  // Create a new project
  app.post('/projects', (req, res) => {
    const { name } = req.body;
    if (!name) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Name is required' } });
    if (Object.values(projectsRepo).some(p => p.name === name)) return res.status(409).json({ error: { code: 'DUPLICATE_PROJECT', message: 'Project with this name already exists' } });

    const projectId = crypto.randomUUID();
    projectsRepo[projectId] = { id: projectId, name };
    res.status(201).json({ project: projectsRepo[projectId] });
  });

  // Get all projects
  app.get('/projects', (req, res) => {
    const projects = Object.values(projectsRepo);
    res.status(200).json({ projects });
  });

  // Get a project by ID
  app.get('/projects/:projectId', (req, res) => {
    const { projectId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    res.status(200).json({ project: projectsRepo[projectId] });
  });
};

module.exports = (app, { projectsRepo, tasksRepo, crypto }) => {
  // Create a new task for a project
  app.post('/projects/:projectId/tasks', (req, res) => {
    const { projectId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    const { title } = req.body;
    if (!title) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Title is required' } });

    const taskId = crypto.randomUUID();
    tasksRepo[taskId] = { id: taskId, projectId, title, status: 'pending' };
    res.status(201).json({ task: tasksRepo[taskId] });
  });

  // Get all tasks for a project
  app.get('/projects/:projectId/tasks', (req, res) => {
    const { projectId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    const tasks = Object.values(tasksRepo).filter(task => task.projectId === projectId);
    res.status(200).json({ tasks });
  });

  // Get tasks by status for a project
  app.get('/projects/:projectId/tasks', (req, res) => {
    const { projectId } = req.params;
    const { status } = req.query;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    const tasks = Object.values(tasksRepo).filter(task => task.projectId === projectId && task.status === status);
    res.status(200).json({ tasks });
  });

  // Update a task's status
  app.patch('/projects/:projectId/tasks/:taskId', (req, res) => {
    const { projectId, taskId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });
    if (!tasksRepo[taskId] || tasksRepo[taskId].projectId !== projectId) return res.status(404).json({ error: { code: 'TASK_NOT_FOUND', message: 'Task not found' } });

    const { status } = req.body;
    if (status && ['pending', 'done'].includes(status)) {
      tasksRepo[taskId].status = status;
      res.status(200).json({ task: tasksRepo[taskId] });
    } else {
      return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Invalid status' } });
    }
  });
};

module.exports = (app, { projectsRepo, membersRepo, crypto }) => {
  // Add a member to a project
  app.post('/projects/:projectId/members', (req, res) => {
    const { projectId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    const { name } = req.body;
    if (!name) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Name is required' } });

    const memberId = crypto.randomUUID();
    membersRepo[memberId] = { id: memberId, projectId, name };
    res.status(201).json({ member: membersRepo[memberId] });
  });

  // Get all members for a project
  app.get('/projects/:projectId/members', (req, res) => {
    const { projectId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });

    const members = Object.values(membersRepo).filter(member => member.projectId === projectId);
    res.status(200).json({ members });
  });
};

module.exports = (app, { projectsRepo, tasksRepo, commentsRepo, crypto }) => {
  // Add a comment to a task
  app.post('/projects/:projectId/tasks/:taskId/comments', (req, res) => {
    const { projectId, taskId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });
    if (!tasksRepo[taskId] || tasksRepo[taskId].projectId !== projectId) return res.status(404).json({ error: { code: 'TASK_NOT_FOUND', message: 'Task not found' } });

    const { message } = req.body;
    if (!message) return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Message is required' } });

    const commentId = crypto.randomUUID();
    commentsRepo[commentId] = { id: commentId, taskId, message };
    res.status(201).json({ comment: commentsRepo[commentId] });
  });

  // Get all comments for a task
  app.get('/projects/:projectId/tasks/:taskId/comments', (req, res) => {
    const { projectId, taskId } = req.params;
    if (!projectsRepo[projectId]) return res.status(404).json({ error: { code: 'PROJECT_NOT_FOUND', message: 'Project not found' } });
    if (!tasksRepo[taskId] || tasksRepo[taskId].projectId !== projectId) return res.status(404).json({ error: { code: 'TASK_NOT_FOUND', message: 'Task not found' } });

    const comments = Object.values(commentsRepo).filter(comment => comment.taskId === taskId);
    res.status(200).json({ comments });
  });
};
